//generate a gb2312 to unicode lookup table
//gb2312 encoding contains most if not all simplified Chinese characters
function generateGb2312LookupTable(){
  var codes = [];
  for(var i=0xb0;i<=0xf7;i++){
    for(var j=0xa0;j<0xfe;j++){
        codes.push(i,j);
    }
  }
  const str = new TextDecoder('gb2312').decode(new Uint8Array(codes));

  // gbk to unicode table
  var table = new Uint16Array(65536)
  for (var i = 0; i < str.length; i++) {
    table[str.charCodeAt(i)] = (codes[i*2]<<8)|codes[i*2+1];
  }
  return table;
}

var gbTable = generateGb2312LookupTable();

//generate a big5 to unicode lookup table
//big5 encoding contains most if not all traditional Chinese characters
function generateBig5LookupTable(){
  var decoder = new TextDecoder('big5');
  var codes = [];
  var buf = new Uint8Array(2);
  for(var i=0x8140;i<=0xfefe;i++){
    buf[0] = (i&0xff00)>>8;
    buf[1] = i&0xff;
    var c = decoder.decode(buf);
    if(c.length==1 && c!='\ufffd')
      codes.push(buf[0],buf[1]);
  }
  const str = decoder.decode(new Uint8Array(codes));

  // big5 to unicode table
  var table = new Uint16Array(65536)
  for (var i = 0; i < str.length; i++) {
    table[str.charCodeAt(i)] = (codes[i*2]<<8)|codes[i*2+1];
  }
  return table;
}

var big5Table = generateBig5LookupTable();

