//kanji are sorted using their shift-jis code
function kanjiSortFn(a,b){
  return kanji.indexOf(a)-kanji.indexOf(b);
}

//Generate a romaji-kanji lookup table.
//The table merges kun and on reading, so you can input using both
function generateRomajiTable(){
  var table = {};
  for(var i=0;i<kanji.length;i++){
    var or = kanji_onReading[i];
    if(!(or instanceof Array)){
      or = [or];
    }
    var kr = kanji_kunReading[i];
    if(!(kr instanceof Array)){
      kr = [kr];
    }
    var ar = or.concat(kr);
    for(var k of ar){
      if(k!=kanji[i]){
        table[k] = table[k]||[];
        table[k].push(kanji[i]);
      }
    }
  }
  for(var k in table){
    table[k] = Array.from(new Set(table[k]));
  }
  return table;
}

var romajiTable = generateRomajiTable();

