// Window_NameEdit
//
// The window for editing an actor's name on the name input screen.

Window_NameEdit._inputModeLocked = PluginManager.parameters(plugin_name)['lock input mode']==='true';
Window_NameEdit._defaultTypeInputMode = PluginManager.parameters(plugin_name)['default type input mode']==='true';
Window_NameEdit._input = document.createElement('input');
Window_NameEdit._input.type = 'text';
Window_NameEdit._input.style.position = 'absolute';
Window_NameEdit._input.style.left = '-999px';
Window_NameEdit._input.style.top = '-999px';
Window_NameEdit._input.style.width = '1px';
Window_NameEdit._input.style.height = '1px';
Window_NameEdit._input.style.opacity = '0.0';
Window_NameEdit._input.autofocus = true;
document.body.append(Window_NameEdit._input);
Window_NameEdit._inputMode = Window_NameEdit._defaultTypeInputMode;

Window_Base.prototype.iconWidth = function(){
  if(isMV) return Window_Base._iconWidth;
  if(isMZ) return ImageManager.iconWidth;
  return 32;
};

Window_Base.prototype.iconHeight = function(){
  if(isMV) return Window_Base._iconHeight;
  if(isMZ) return ImageManager.iconHeight;
  return 32;
};

Window_NameEdit.prototype.windowWidth = function() {
    return 640;
};

Window_NameEdit.prototype.charWidth = function(index) {
    var text = this._name[index]||' ';
    return this.textWidth(text);
};

Window_NameEdit.prototype.left = function() {
    return this.faceWidth() + 24 + this.iconWidth();
};

Window_NameEdit.prototype.itemRect = function(index) {
  var left = 0;
  for(var i=0;i<index;i++){
    left += this.charWidth(i);
  }
  return new Rectangle(
      this.left() + left,
      54,
      this.charWidth(index),
      this.lineHeight()
  );
};

(function(alias){
Window_NameEdit.prototype.refresh = function() {
    alias.call(this);
    var rect = this.itemRect(0);
    this.changePaintOpacity(Window_NameEdit._inputMode);
    this.contents.context.filter = Window_NameEdit._inputMode?'none':'grayscale()';
    this.drawIcon(245, rect.x - this.iconWidth() - 2 , rect.y + 2); 
    this.contents.context.filter = 'none';
    this.changePaintOpacity(true);
};
})(Window_NameEdit.prototype.refresh);

if(isMZ)
Window_Scrollable.prototype.isTouchedInputIcon = function() {
    const touchPos = new Point(TouchInput.x, TouchInput.y);
    const localPos = this.worldTransform.applyInverse(touchPos);
    var rect = this.itemRect(0);
    rect.x -= this.iconWidth() + 2 - this.innerRect.x;
    rect.y += 2 + this.innerRect.y;
    rect.width = this.iconWidth();
    rect.height = this.iconHeight();
    return rect.contains(localPos.x, localPos.y);
};

if(isMV)
Window_NameEdit.prototype.isTouchedInputIcon = function() {
    var x = this.canvasToLocalX(TouchInput.x);
    var y = this.canvasToLocalY(TouchInput.y);
    var rect = this.itemRect(0);
    rect.x -= this.iconWidth() + 2 - this._padding;
    rect.y += 2 + this._padding;
    rect.width = this.iconWidth();
    rect.height = this.iconHeight();
    return x >= rect.x && y >= rect.y && x < rect.x + rect.width && y < rect.y + rect.height;
};

Window_NameEdit.prototype.toggleInputMode = function(mode){
  Window_NameEdit._inputMode = (mode==undefined)?(!Window_NameEdit._inputMode):mode;
  var input = Window_NameEdit._input;
  if(Window_NameEdit._inputMode){
    this.activate();
    SceneManager._scene._inputWindow.deactivate();
    SceneManager._scene._inputWindow.hide();
    input.focus();
    const crect = Graphics._canvas.getBoundingClientRect();
    input.style.left = TouchInput.x*Graphics._realScale + crect.x + 'px';
    input.style.top = TouchInput.y*Graphics._realScale + crect.y + 'px';
    input.maxLength = this._maxLength;
    input.value = this._name;
    input.oninput = (function(e){
      this._name = input.value;
      this.refresh();
    }).bind(this);
    input.onkeydown = input.onkeyup =  (function(e){
      this._index = input.selectionEnd;
      this.refresh();
    }).bind(this);
    input.onkeypress =  (function(e){
      if(e.keyCode==13) SceneManager._scene._inputWindow.onNameOk();
    }).bind(this);
    input.onblur=function(e) {
      e.preventDefault();
      this.focus();
    };
    this.refresh();
  }else{
    this.deactivate();
    SceneManager._scene._inputWindow.activate();
    SceneManager._scene._inputWindow.show();
    input.blur();
    input.onchange = input.onkeydown = input.onkeyup = input.onkeypress = input.onblur = null;
    this._index = this._name.length;
    this.refresh();
  }
};

(function(alias){
Window_NameEdit.prototype.update = function(){
  alias.call(this);
  if(Window_NameEdit._inputModeLocked) return;
  if (TouchInput.isTriggered()){
    if(this.isTouchedInputIcon()){
      this.toggleInputMode();
    }
  }
};
})(Window_NameEdit.prototype.update);

