Scene_Name.prototype.start = function() {
    Scene_MenuBase.prototype.start.call(this);
    this._editWindow.toggleInputMode(Window_NameEdit._inputMode);
};

(function(alias){
Scene_Name.prototype.terminate = function(){
  alias.call(this);
  //IMPORTANT!, make sure input mode is off of the edit window
  this._editWindow.toggleInputMode(false);
};
})(Scene_Name.prototype.terminate);
