//sort function that puts gb2312 characters before others
function hanziSortGb2312(a,b){
  a = gbTable[a.charCodeAt(0)]||(0x10ffff+a.charCodeAt(0));
  b = gbTable[b.charCodeAt(0)]||(0x10ffff+b.charCodeAt(0));
  return a-b;
};

//sort function that puts big5 characters before others
function hanziSortBig5(a,b){
  a = big5Table[a.charCodeAt(0)]||(0x10ffff+a.charCodeAt(0));
  b = big5Table[b.charCodeAt(0)]||(0x10ffff+b.charCodeAt(0));
  return a-b;
};

//build and sort the hanzi tables
function buildHanziTables(pinyin,sort){
  var tab = [];
  var p = 0;
  function pushbtns(){
    tab.push('[Back]');
    tab.push(sort==hanziSortBig5?'[Zhuyin]':'[Pinyin]');
    tab.push('[Prev]');
    tab.push('[Next]');
    tab.push('[OK]');
    Window_NameInput['HANZI' + pinyin + p] = tab;
    Window_NameInput.hanziTables.push(tab);
    tab = [];
    p++;
  }
  pinyin_dict[pinyin].sort(sort||hanziSortGb2312);
  for(var k of pinyin_dict[pinyin]){
    if(!hanziFilterFn(k)) continue;
    tab.push(k);
    if(tab.length==85) pushbtns();
  }
  if(tab.length){
    for(var i=tab.length;i<85;i++){
      tab.push('　');
    }
    pushbtns();
  }
  return p;
}

//the table is unused for now, 
//Window_NameInput.pinyinTables = [];
function buildPinyinTables(sort){
  var tab = [];
  var p = 0;
  function pushbtns(){
    tab.push('[Back]');
    tab.push(sort==hanziSortBig5?'[Zhuyin]':'[Pinyin]');
    tab.push('[Prev]');
    tab.push('[Next]');
    tab.push('[OK]');
    Window_NameInput['PINYIN'+ p] = tab;
    //Window_NameInput.pinyinTables.push(tab);
    tab = [];
    p++;
  }
  for(var k in pinyin_dict){
    tab.push(k);
    buildHanziTables(k,sort);
    if(tab.length==85) pushbtns();
  }
  if(tab.length){
    for(var i=tab.length;i<85;i++){
      tab.push('　');
    }
    pushbtns();
  }
  return p;
}

Window_NameInput.pinyinPageCount = buildPinyinTables();

function buildJamoTable(){
  var jamos = [];
  jamos.push(...jamoTable.initial,...jamoTable.medial,...jamoTable.final);
  jamos = Array.from(new Set(jamos));
  for(var i=0;i<jamos.length;i++){
    Window_NameInput.HANGUL[i] = jamos[i];
  }
}

buildJamoTable();

